import { TooltipValueContent } from '../section-components/TooltipValueContent/TooltipValueContent.js';

/**
 * @internal
 * Object exposing the slots config for the custom tooltip.
 * It contains:
 * - sections components (Header, Subheader, Body, Footer, Item): sections of the tooltip
 * - subsections components (Symbol, Content, Value): flex wrappers for the Item
 * - templates: wrappers for the tooltip atoms
 */
export const ChartTooltipSlots = {
  // section components
  Header: TooltipHeader,
  Subheader: TooltipSubheader,
  Body: TooltipBody,
  Item: TooltipItem,
  Footer: TooltipFooter,
  // Item subsections
  Symbol: TooltipSymbolContent,
  Content: TooltipInfoContent,
  Value: TooltipValueContent,
} as const;

/**
 * @internal
 * Object exposing the atoms the custom tooltip.
 * It contains:
 * - tooltip atoms
 * - tooltip shapes
 */
export const ChartTooltipAtoms = {
  // atoms
  Chip: ChipAtom,
  DurationChipAtom,
  Primary: PrimaryAtom,
  Secondary: SecondaryAtom,
  Symbol: SymbolAtom,
  // shapes
  Bubble: BubbleShape,
  Emoji: EmojiShape,
  Icon: IconShape,
  MultiDataPoint: MultiDataPointShape,
  SingleDataPoint: SingleDataPointShape,
} as const;

/**
 * @internal
 * Object exposing the templates for the custom tooltip
 */
export const ChartTooltipTemplate = {
  GeoItem,
  Text: TooltipText,
  SeriesItem,
  ActionItem,
  TimeFrameHeader,
  TimestampHeader,
  RangeHeader,
  TextHeader,
  EventItem,
  KeyValue,
  DurationChip,
};

/** @internal */
export type ChartTooltipSlotsType = typeof ChartTooltipSlots;
/** @internal */
export type ChartTooltipAtomsType = typeof ChartTooltipAtoms;
/** @internal */
export type ChartTooltipTemplateType = typeof ChartTooltipTemplate;
